#include <stdio.h>
#include <stdlib.h>

int main() {
    int value = 42;
    int *ptr = &value;
    printf("Value: %d\n", *ptr);

    int *dyn = (int*)malloc(sizeof(int));
    if (dyn != NULL) {
        *dyn = 100;
        printf("Dynamic: %d\n", *dyn);
        free(dyn);
    }
    return 0;
}
